import{_ as t,a,b as r,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Ajouter un canal compatible S3","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/s3.md","filePath":"fr-FR/upload/s3.md","lastUpdated":1781962217000}'),l={name:"fr-FR/upload/s3.md"};function c(u,e,p,h,m,b){return o(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="ajouter-un-canal-compatible-s3" tabindex="-1">Ajouter un canal compatible S3 <a class="header-anchor" href="#ajouter-un-canal-compatible-s3" aria-label="Permalink to &quot;Ajouter un canal compatible S3&quot;">​</a></h1><p>Le canal S3 permet d’utiliser un stockage objet compatible avec l’API S3.</p><p>Il convient pour Cloudflare R2, Backblaze B2, MinIO, AWS S3 et d’autres services compatibles.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>URL de l’API du stockage</td></tr><tr><td>Bucket</td><td>Bucket où les fichiers seront enregistrés</td></tr><tr><td>Region</td><td>Région du stockage ; avec Cloudflare R2, souvent <code>auto</code></td></tr><tr><td>Access Key ID</td><td>Clé d’accès</td></tr><tr><td>Secret Access Key</td><td>Clé secrète</td></tr><tr><td>Domaine CDN</td><td>Optionnel, pour des URL publiques personnalisées</td></tr></tbody></table><p>Exemple avec Cloudflare R2 via l’API S3 :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://votreAccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: nom-du-bucket</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="ou-ajouter" tabindex="-1">Où ajouter <a class="header-anchor" href="#ou-ajouter" aria-label="Permalink to &quot;Où ajouter&quot;">​</a></h2><ol><li>Ouvrez Paramètres système.</li><li>Entrez dans Paramètres d’upload.</li><li>Cliquez sur <code>Ajouter un canal</code>.</li><li>Choisissez <code>S3</code>.</li></ol><h2 id="champs" tabindex="-1">Champs <a class="header-anchor" href="#champs" aria-label="Permalink to &quot;Champs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Champ</th><th>Description</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>R2-S3</code> ou <code>MinIO</code></td></tr><tr><td>Endpoint</td><td>URL S3 complète avec <code>https://</code></td></tr><tr><td>Domaine CDN personnalisé</td><td>Optionnel ; utilisé pour générer les liens</td></tr><tr><td>Bucket</td><td>Nom du bucket</td></tr><tr><td>Region</td><td><code>auto</code> pour R2 ; selon la documentation pour les autres fournisseurs</td></tr><tr><td>Access Key ID</td><td>Clé d’accès</td></tr><tr><td>Secret Access Key</td><td>Clé secrète</td></tr><tr><td>Path-style access</td><td>Seulement si le fournisseur l’exige</td></tr><tr><td>Limite de capacité</td><td>Optionnel</td></tr></tbody></table><h2 id="creer-des-cles-s3-pour-r2" tabindex="-1">Créer des clés S3 pour R2 <a class="header-anchor" href="#creer-des-cles-s3-pour-r2" aria-label="Permalink to &quot;Créer des clés S3 pour R2&quot;">​</a></h2><p>Dans le Cloudflare Dashboard, ouvrez <code>R2 Object Storage</code> puis la gestion des API Tokens.</p><p>![Entrée R2 API Token](../../image/upload/s3/r2 api token入口.png)</p><p>Créez un token R2 ayant accès au bucket cible.</p><p><img src="`+t+'" alt="Créer API Token" loading="lazy"></p><p>Copiez <code>Access Key ID</code> et <code>Secret Access Key</code>.</p><p><img src="'+a+'" alt="Copier les valeurs" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><ol><li>Saisissez <code>Endpoint</code>, <code>Bucket</code> et <code>Region</code>.</li><li>Saisissez Access Key ID et Secret Access Key.</li><li>Si vous utilisez un CDN, renseignez le domaine personnalisé.</li><li>Activez Path-style access uniquement si le service l’exige.</li><li>Enregistrez.</li></ol><p><img src="'+r+'" alt="Configuration S3" loading="lazy"></p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Point</th><th>État attendu</th></tr></thead><tbody><tr><td>Carte du canal</td><td>Apparaît après enregistrement</td></tr><tr><td>Upload de test</td><td>Crée un objet dans le bucket</td></tr><tr><td>Lien</td><td>L’URL renvoyée par ImgBed s’ouvre correctement</td></tr><tr><td>Capacité</td><td>Si une limite est configurée, l’usage s’affiche</td></tr></tbody></table><p><img src="'+s+'" alt="Capacité S3" loading="lazy"></p><p>Les statistiques de capacité S3 sont calculées à partir des enregistrements locaux D1 d’ImgBed, pas via un scan en temps réel du bucket.</p><h2 id="erreurs-courantes" tabindex="-1">Erreurs courantes <a class="header-anchor" href="#erreurs-courantes" aria-label="Permalink to &quot;Erreurs courantes&quot;">​</a></h2><ul><li>Endpoint sans <code>https://</code>.</li><li>Bucket ou Region incorrect.</li><li>Access Key sans droit d’écriture.</li><li>Le fournisseur exige Path-style access.</li><li>CDN mal relié au bucket.</li></ul>',27)])])}const C=d(l,[["render",c]]);export{k as __pageData,C as default};
